import json
import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        decoded_str = decoded.decode('utf-8')
        token = json.loads(decoded_str)
        if isinstance(token, dict) and 'data' in token:
            return token['data']
        else:
            return None
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        return None

from flask import request, Flask
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    data_str = request.args.get('data')
    if not data_str:
        return "Missing YAML data", 400
    try:
        data = yaml.safe_load(data_str)
    except yaml.YAMLError as e:
        return f"Invalid YAML: {e}", 400
    return data
